BEGIN TRANSACTION;

drop schema if exists "tornei_tennis" cascade;

create schema "tornei_tennis";
set search_path to "tornei_tennis";

CREATE TABLE GIOCATORE (
    IdG VARCHAR(50) PRIMARY KEY,
    Nome VARCHAR(255),
    Cognome VARCHAR(255),
    Genere CHAR(1),
    DataN DATE,
    Nazione VARCHAR(100)
);

CREATE TABLE TORNEO (
    IdT VARCHAR(50) PRIMARY KEY,
    NomeT VARCHAR(255),
    Luogo VARCHAR(255),
    DataI DATE,
    DataF DATE,
    NumTurni INTEGER,
    Tipo VARCHAR(100),
    Terreno VARCHAR(100)
);

CREATE TABLE CATEGORIA (
    IdCat VARCHAR(50) PRIMARY KEY,
    NomeCategoria VARCHAR(100),
    GenereCategoria CHAR(1)
);

CREATE TABLE REGISTRAZIONE (
    IdT VARCHAR(50) REFERENCES TORNEO(IdT),
    IdCat VARCHAR(50) REFERENCES CATEGORIA(IdCat),
    NumRegistrazione INTEGER,
    DataRegistrazione DATE,
    TestaDiSerie BOOLEAN,
    PRIMARY KEY (IdT, IdCat, NumRegistrazione)
);

CREATE TABLE GIOCAIN (
    IdT VARCHAR(50),
    IdCat VARCHAR(50),
    NumRegistrazione INTEGER,
    IdG VARCHAR(50) REFERENCES GIOCATORE(IdG),
    PRIMARY KEY (IdT, IdCat, NumRegistrazione, IdG),
    FOREIGN KEY (IdT, IdCat, NumRegistrazione) REFERENCES REGISTRAZIONE(IdT, IdCat, NumRegistrazione)
);

-- No INSERT statements (exam PDF source, no data instances provided)
-- Note: NomeCategoria values include: singolo, doppio, squadra

COMMIT;
